// src/pages/Home.jsx (VERSÃO CORRIGIDA)

import Header from '../../components/Layout/Header';
import Footer from '../components/layout/Footer/Footer';
import ServiceCard from '../components/services/ServiceCard'; // <-- IMPORTANTE: Importamos o Card, não a Lista

// Importamos todos os dados de uma vez usando o "barril" (index.js)
import * as serviceData from '../data';

const Home = () => {
  return (
    <>
      <Header />
      <main className="page-container">
        <div className="container">

          {/* ESTE É O ÚNICO GRID QUE ENVOLVE TUDO */}
          <div className="service-grid">

            {/* Título da Categoria 1 */}
            <h2 className="grid-section-title">Limpeza e Manutenção</h2>
            {/* Cards da Categoria 1 */}
            {serviceData.cleaningServices.map((service) => (
              <ServiceCard key={service.title} {...service} />
            ))}

            {/* Título da Categoria 2 */}
            <h2 className="grid-section-title">Sistema e Performance</h2>
            {/* Cards da Categoria 2 */}
            {serviceData.performanceServices.map((service) => (
              <ServiceCard key={service.title} {...service} />
            ))}

            {/* Título da Categoria 3 */}
            <h2 className="grid-section-title">Recuperação e Backup</h2>
            {/* Cards da Categoria 3 */}
            {serviceData.dataServices.map((service) => (
              <ServiceCard key={service.title} {...service} />
            ))}

            {/* Título da Categoria 4 */}
            <h2 className="grid-section-title">Empresarial (B2B)</h2>
            {/* Cards da Categoria 4 */}
            {serviceData.b2bServices.map((service) => (
              <ServiceCard key={service.title} {...service} />
            ))}

            {/* Título da Categoria 5 */}
            <h2 className="grid-section-title">Nossas Garantias</h2>
            {/* Cards da Categoria 5 */}
            {serviceData.warrantyServices.map((service) => (
              <ServiceCard key={service.title} {...service} />
            ))}

          </div> {/* FIM DO GRID ÚNICO */}

        </div>
      </main>
      <Footer />
    </>
  );
};

export default Home;
